#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <assert.h>
#include <omp.h>

#define THREADS_PER_DIM 16
#define BLOCKS_PER_DIM 16
#define THREADS_PER_BLOCK (THREADS_PER_DIM*THREADS_PER_DIM)

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

#define ASSUMED_NR_CLUSTERS 32

#define CPU_DELTA_REDUCE
#define CPU_CENTER_REDUCE

extern int setup(int argc, char** argv);

unsigned int num_threads_perdim = THREADS_PER_DIM;
unsigned int num_blocks_perdim = BLOCKS_PER_DIM;
unsigned int num_threads = num_threads_perdim*num_threads_perdim;
unsigned int num_blocks = num_blocks_perdim*num_blocks_perdim;

int    *membership_new;
float  *feature_d;
float  *feature_flipped_d;
int    *membership_d;
float  *block_new_centers;
float  *clusters_d;
float  *block_clusters_d;
int    *block_deltas_d;

float **features_global;
int    *membership_global;
float  **clusters_global;
int     *new_centers_len_global;
float  **new_centers_global;
int     nfeatures_global;
int     npoints_global;
int     nclusters_global;

extern void allocateMemory(int npoints, int nfeatures, int nclusters, float **features)
{
    num_blocks = npoints / num_threads;
    if (npoints % num_threads > 0)
        num_blocks++;

    num_blocks_perdim = (unsigned int)sqrt((double) num_blocks);
    while (num_blocks_perdim * num_blocks_perdim < num_blocks)
        num_blocks_perdim++;

    num_blocks = num_blocks_perdim*num_blocks_perdim;

    membership_new = (int*) malloc(npoints * sizeof(int));
    for(int i=0;i<npoints;i++) {
        membership_new[i] = -1;
    }

    block_new_centers = (float *) malloc(nclusters*nfeatures*sizeof(float));

    feature_flipped_d = (float *) malloc(npoints*nfeatures*sizeof(float));
    memcpy(feature_flipped_d, features[0], npoints*nfeatures*sizeof(float));

    feature_d = (float *) malloc(npoints*nfeatures*sizeof(float));

    int total_elements = npoints * nfeatures;
    #pragma omp parallel for
    for (int idx = 0; idx < total_elements; idx++) {
        int point_id = idx / nfeatures;
        int i = idx % nfeatures;
        int input_idx = point_id * nfeatures + i;
        int output_idx = point_id + npoints * i;
        feature_d[output_idx] = feature_flipped_d[input_idx];
    }

    membership_d = (int*) malloc(npoints*sizeof(int));
    clusters_d = (float*) malloc(nclusters*nfeatures*sizeof(float));

    block_deltas_d = (int *) malloc(num_blocks_perdim * num_blocks_perdim * sizeof(int));

    block_clusters_d = (float *) malloc(
        num_blocks_perdim * num_blocks_perdim *
        nclusters * nfeatures * sizeof(float));
}

extern void deallocateMemory()
{
    free(membership_new);
    free(block_new_centers);
    free(feature_d);
    free(feature_flipped_d);
    free(membership_d);
    free(clusters_d);
    free(block_clusters_d);
    free(block_deltas_d);
}

int main(int argc, char** argv)
{
    setup(argc, argv);
    return 0;
}

extern int kmeansCuda(float  **feature,
                      int      nfeatures,
                      int      npoints,
                      int      nclusters,
                      int     *membership,
                      float  **clusters,
                      int     *new_centers_len,
                      float  **new_centers)
{
    int delta = 0;
    int i, j;

    features_global = feature;
    membership_global = membership;
    clusters_global = clusters;
    new_centers_len_global = new_centers_len;
    new_centers_global = new_centers;
    nfeatures_global = nfeatures;
    npoints_global = npoints;
    nclusters_global = nclusters;

    memcpy(membership_d, membership_new, npoints*sizeof(int));
    memcpy(clusters_d, clusters[0], nclusters*nfeatures*sizeof(float));

    int total_points = npoints;
    int total_blocks = num_blocks_perdim * num_blocks_perdim;
    int threads_per_block = num_threads;

    #pragma omp parallel for schedule(static)
    for (int block_idx = 0; block_idx < total_blocks; block_idx) {
        int block_x = block_idx % num_blocks_perdim;
        int block_y = block_idx / num_blocks_perdim;
        int block_id = block_y * num_blocks_perdim + block_x;

        int block_delta = 0;
        float *local_block_clusters = (float*)calloc(nclusters * nfeatures, sizeof(float));

        #pragma omp parallel for schedule(static)
        for (int t = 0; t < threads_per_block; t++) {
            int point_id = block_id * threads_per_block + t;

            if (point_id < npoints) {
                int index = -1;
                float min_dist = FLT_MAX;

                for (int i_cluster = 0; i_cluster < nclusters; i_cluster++) {
                    float ans = 0.0;
                    int cluster_base_index = i_cluster * nfeatures;

                    for (int j_feat = 0; j_feat < nfeatures; j_feat++) {
                        int addr = point_id + j_feat * npoints;
                        float diff = feature_d[addr] - clusters_d[cluster_base_index + j_feat];
                        ans += diff * diff;
                    }

                    if (ans < min_dist) {
                        min_dist = ans;
                        index = i_cluster;
                    }
                }

                if (membership_d[point_id] != index) {
                    block_delta++;
                }
                membership_d[point_id] = index;

                for (int j_feat = 0; j_feat < nfeatures; j_feat++) {
                    local_block_clusters[index * nfeatures + j_feat] += feature[point_id][j_feat];
                }
            }
        }

        block_deltas_d[block_idx] = block_delta;

        for (int k = 0; k < nclusters * nfeatures; k++) {
            block_clusters_d[block_idx * nclusters * nfeatures + k] = local_block_clusters[k];
        }
        free(local_block_clusters);
    }

    memcpy(membership_new, membership_d, npoints*sizeof(int));

    delta = 0;
    for (i = 0; i < npoints; i++) {
        int cluster_id = membership_new[i];
        new_centers_len[cluster_id]++;
        if (membership_new[i] != membership[i]) {
#ifdef CPU_DELTA_REDUCE
            delta++;
#endif
            membership[i] = membership_new[i];
        }
#ifdef CPU_CENTER_REDUCE
        for (j = 0; j < nfeatures; j++) {
            new_centers[cluster_id][j] += feature[i][j];
        }
#endif
    }

#ifdef BLOCK_DELTA_REDUCE
    for(i = 0; i < num_blocks_perdim * num_blocks_perdim; i++) {
        delta += block_deltas_d[i];
    }
#endif

#ifdef BLOCK_CENTER_REDUCE
    for(int j = 0; j < nclusters; j++) {
        for(int k = 0; k < nfeatures; k++) {
            block_new_centers[j*nfeatures + k] = 0.f;
        }
    }

    for(i = 0; i < num_blocks_perdim * num_blocks_perdim; i++) {
        for(int j = 0; j < nclusters; j++) {
            for(int k = 0; k < nfeatures; k++) {
                block_new_centers[j*nfeatures + k] += block_clusters_d[i * nclusters*nfeatures + j * nfeatures + k];
            }
        }
    }

#ifdef CPU_CENTER_REDUCE
#endif

#ifdef BLOCK_CENTER_REDUCE
    for(int j = 0; j < nclusters; j++) {
        for(int k = 0; k < nfeatures; k++)
            new_centers[j][k] = block_new_centers[j*nfeatures + k];
    }
#endif
#endif

    return delta;
}
